    53→/**
    54→ * Process optimizer job
    55→ *
    56→ * Fetches required data, builds input, runs optimization,
    57→ * and stores/broadcasts results.
    58→ */
    59→export async function processOptimizerJob(
    60→  context: WorkerJobContext<OptimizerJobData>
    61→): Promise<OptimizerFullResult> {
    62→  return withSpan('worker.optimizer.process', async (span) => {
    63→    const { id, data } = context;
    64→    const { date, fleetId, constraints, timeoutMs } = data;
    65→
    66→    span.setAttribute('jobId', id);
    67→    span.setAttribute('date', date);
    68→    span.setAttribute('fleetId', fleetId);
    69→    span.setAttribute('hasConstraints', !!constraints);
    70→
    71→    log.info({ jobId: id, date, fleetId }, 'Processing optimizer job');
    72→
    73→    // Update progress: fetching data
    74→    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 10 });
    75→    await context.log('Fetching trains and routes from database');
    76→
    77→    // Build optimizer input
    78→    const input = await buildOptimizerInput(date, fleetId, constraints, timeoutMs);
    79→
    80→    // Update progress: optimizing
    81→    await context.updateProgress({ stage: 'OPTIMIZING', percent: 30 });
    82→    await context.log(`Starting optimization for ${input.trains.length} trains, ${input.routes.length} routes`);
    83→
    84→    // Track optimization start time for elapsed calculation
    85→    const optimizeStartTime = Date.now();
    86→
    87→    // Run optimization with progress callback
    88→    const result = await runAssignmentOptimizer.optimize(input, async (progress) => {
    89→      const percent = 30 + Math.floor(progress.percent * 0.6);
    90→
    91→      // Update BullMQ job progress
    92→      await context.updateProgress({
    93→        stage: 'OPTIMIZING',
    94→        percent,
    95→        objective: progress.currentObjective,
    96→        feasible: progress.feasible,
    97→      });
    98→
    99→      // Broadcast to WebSocket clients for real-time UI updates
   100→      await broadcastOptimizerProgress({
   101→        jobId: id,
   102→        percent,
   103→        currentObjective: progress.currentObjective,
   104→        feasible: progress.feasible,
   105→        elapsedMs: Date.now() - optimizeStartTime,
   106→      });
   107→    });
   108→
   109→    // Update progress: storing results
   110→    await context.updateProgress({ stage: 'STORING_RESULTS', percent: 95 });
   111→    await context.log(`Optimization complete: ${result.summary.trainsAssigned} trains assigned`);
   112→
   113→    // Store run assignments to database for historical analysis
   114→    await storeOptimizationResults(date, input.requestId, result);
   115→
   116→    // Broadcast completion to WebSocket clients
   117→    // Map FALLBACK status to FEASIBLE for WebSocket compatibility
   118→    const wsStatus = result.status === 'FALLBACK' ? 'FEASIBLE' : result.status;
   119→    await broadcastOptimizerComplete({
   120→      jobId: id,
   121→      status: wsStatus as 'OPTIMAL' | 'FEASIBLE' | 'INFEASIBLE' | 'TIMEOUT' | 'ERROR',
   122→      solveTimeMs: result.solveTimeMs,
   123→      assignmentCount: result.summary.trainsAssigned,
   124→      unassignedCount: result.summary.trainsUnassigned,
   125→    });
   126→
   127→    // Update metrics
   128→    optimizerMetrics.trainsAssigned
   129→      .labels(fleetId)
   130→      .set(result.summary.trainsAssigned);
   131→
   132→    log.info(
   133→      {
   134→        jobId: id,
   135→        status: result.status,
   136→        trainsAssigned: result.summary.trainsAssigned,
   137→        trainsUnassigned: result.summary.trainsUnassigned,
   138→        solveTimeMs: result.solveTimeMs,
   139→      },
   140→      'Optimizer job complete'
   141→    );
   142→
   143→    return result;
   144→  });
   145→}
