   147→/**
   148→ * Build optimizer input from database
   149→ */
   150→async function buildOptimizerInput(
   151→  date: string,
   152→  fleetId: string,
   153→  constraints?: OptimizerJobData['constraints'],
   154→  timeoutMs?: number
   155→): Promise<OptimizerFullInput> {
   156→  const requestId = crypto.randomUUID();
   157→
   158→  // Fetch fleet info
   159→  const fleet = await db.query.fleets.findFirst({
   160→    where: eq(fleets.id, fleetId),
   161→  });
   162→
   163→  if (!fleet) {
   164→    throw new ValidationError('Fleet not found', {
   165→      field: 'fleetId',
   166→      context: { fleetId },
   167→    });
   168→  }
   169→
   170→  // Fetch trains for this fleet
   171→  const trainRecords = await db.query.trains.findMany({
   172→    where: eq(trains.fleetId, fleetId),
   173→  });
   174→
   175→  if (trainRecords.length === 0) {
   176→    throw new ValidationError('No trains found for fleet', {
   177→      field: 'fleetId',
   178→      context: { fleetId },
   179→    });
   180→  }
   181→
   182→  // Calculate fleet average mileage for target calculation
   183→  const totalMileage = trainRecords.reduce(
   184→    (sum, t) => sum + (t.currentMileageKm || 0),
   185→    0
   186→  );
   187→  const avgMileage = Math.round(totalMileage / trainRecords.length);
   188→
   189→  // Transform trains
   190→  const baseDepotId = fleet.baseDepotId || '';
   191→  const optimizerTrains: OptimizerTrainInput[] = trainRecords.map((t) => ({
   192→    id: t.id,
   193→    trainNumber: t.trainNumber,
   194→    fleetId: t.fleetId,
   195→    currentMileageKm: t.currentMileageKm || 0,
   196→    targetMileageKm: t.targetMileageKm || avgMileage,
   197→    fitnessStatus: t.fitnessStatus as 'FIT' | 'RESTRICTED' | 'GROUNDED',
   198→    restrictions: [],
   199→    homeDepotId: baseDepotId,
   200→    currentDepotId: baseDepotId,
   201→  }));
   202→
   203→  // Fetch routes
   204→  const routeRecords = await db.query.routes.findMany();
   205→
   206→  // Filter routes compatible with this fleet
   207→  const compatibleRoutes = routeRecords.filter((r) => {
   208→    if (!r.allowedFleetIds || r.allowedFleetIds.length === 0) {
   209→      return true; // No restriction means all fleets allowed
   210→    }
   211→    return r.allowedFleetIds.includes(fleetId);
   212→  });
   213→
   214→  // Transform routes
   215→  const optimizerRoutes: OptimizerRouteInput[] = compatibleRoutes.map((r) => ({
   216→    id: r.id,
   217→    routeCode: r.routeCode,
   218→    expectedKmPerDay: r.expectedKmPerDay || 250,
   219→    requiredTrains: r.requiredTrains || 1,
   220→    allowedFleetIds: r.allowedFleetIds || [],
   221→    restrictions: [],
   222→  }));
   223→
   224→  // Build hard constraints
   225→  const hardConstraints: HardConstraint[] = [];
   226→
   227→  // Add unavailable trains from constraints
   228→  if (constraints?.unavailableTrains) {
   229→    for (const trainId of constraints.unavailableTrains) {
   230→      hardConstraints.push({
   231→        type: 'UNAVAILABLE',
   232→        trainId,
   233→        description: 'Train marked as unavailable for this assignment',
   234→      });
   235→    }
   236→  }
   237→
   238→  // Fetch active unavailability events
   239→  const unavailabilityRecords = await db.query.unavailabilityEvents.findMany({
   240→    where: and(
   241→      eq(unavailabilityEvents.status, 'ACTIVE'),
   242→    ),
   243→  });
   244→
   245→  const unavailabilityEventsList: UnavailabilityEvent[] = unavailabilityRecords
   246→    .filter((e) => optimizerTrains.some((t) => t.id === e.trainId))
   247→    .map((e) => ({
   248→      trainId: e.trainId,
   249→      eventType: e.eventType as UnavailabilityEvent['eventType'],
   250→      status: e.status as 'ACTIVE' | 'RESOLVED',
   251→      blocksRunAssignment: e.restrictionLevel === 'GROUNDED',
   252→      description: e.description || undefined,
   253→      externalReference: e.externalReference || undefined,
   254→    }));
   255→
   256→  // Build soft constraints for mileage balancing
   257→  const softConstraints: SoftConstraint[] = optimizerTrains.map((t) => ({
   258→    type: 'MILEAGE_BALANCE' as const,
   259→    trainId: t.id,
   260→    penaltyWeight: 100,
   261→    description: `Mileage balance for ${t.trainNumber}`,
   262→  }));
   263→
   264→  // Fetch service demand
   265→  const demandRecords = await db.query.serviceDemand.findMany({
   266→    where: eq(serviceDemand.fleetId, fleetId),
   267→  });
   268→
   269→  const serviceDemandList: ServiceDemand[] = demandRecords.map((d) => ({
   270→    fleetId: d.fleetId,
   271→    minTrainsRequired: d.minTrainsRequired,
   272→    dayType: d.dayType as ServiceDemand['dayType'],
   273→  }));
   274→
   275→  // Build config
   276→  const config = {
   277→    ...DEFAULT_OPTIMIZER_CONFIG,
   278→    maxSolveTimeSeconds: timeoutMs ? Math.floor(timeoutMs / 1000) : 30,
   279→  };
   280→
   281→  return {
   282→    requestId,
   283→    assignmentDate: date,
   284→    config,
   285→    trains: optimizerTrains,
   286→    routes: optimizerRoutes,
   287→    hardConstraints,
   288→    softConstraints,
   289→    unavailabilityEvents: unavailabilityEventsList,
   290→    serviceDemand: serviceDemandList,
   291→  };
   292→}
