   294→// =============================================================================
   295→// Result Storage
   296→// =============================================================================
   297→
   298→/**
   299→ * Store optimization results to the run_assignments table
   300→ *
   301→ * Persists all train-to-route assignments for historical analysis.
   302→ * Used by RouteUtilizationService to determine typical route assignments
   303→ * for trains, enabling more accurate mileage projections.
   304→ *
   305→ * @param assignmentDate - Date of the assignments
   306→ * @param requestId - UUID grouping this optimization run
   307→ * @param result - Optimizer result containing assignments
   308→ */
   309→async function storeOptimizationResults(
   310→  assignmentDate: string,
   311→  requestId: string,
   312→  result: OptimizerFullResult
   313→): Promise<void> {
   314→  return withSpan('worker.optimizer.storeResults', async (span) => {
   315→    span.setAttribute('requestId', requestId);
   316→    span.setAttribute('assignmentDate', assignmentDate);
   317→    span.setAttribute('assignmentCount', result.assignments.length);
   318→    span.setAttribute('optimizerStatus', result.status);
   319→
   320→    if (result.assignments.length === 0) {
   321→      log.info({ requestId, assignmentDate }, 'No assignments to store');
   322→      return;
   323→    }
   324→
   325→    try {
   326→      // Prepare batch insert values
   327→      const values = result.assignments.map((assignment) => ({
   328→        trainId: assignment.trainId,
   329→        routeId: assignment.routeId,
   330→        assignmentDate,
   331→        requestId,
   332→        optimizerStatus: result.status as 'OPTIMAL' | 'FEASIBLE' | 'FALLBACK' | 'INFEASIBLE',
   333→        score: assignment.score.toFixed(4),
   334→        explanation: JSON.stringify(assignment.explanation),
   335→      }));
   336→
   337→      // Use upsert to handle re-runs for the same date
   338→      // On conflict (trainId + assignmentDate), update the assignment
   339→      await db
   340→        .insert(runAssignments)
   341→        .values(values)
   342→        .onConflictDoUpdate({
   343→          target: [runAssignments.trainId, runAssignments.assignmentDate],
   344→          set: {
   345→            routeId: sql`EXCLUDED.route_id`,
   346→            requestId: sql`EXCLUDED.request_id`,
   347→            optimizerStatus: sql`EXCLUDED.optimizer_status`,
   348→            score: sql`EXCLUDED.score`,
   349→            explanation: sql`EXCLUDED.explanation`,
   350→          },
   351→        });
   352→
   353→      log.info(
   354→        {
   355→          requestId,
   356→          assignmentDate,
   357→          storedCount: result.assignments.length,
   358→          status: result.status,
   359→        },
   360→        'Run assignments stored successfully'
   361→      );
   362→    } catch (error) {
   363→      log.error(
   364→        {
   365→          requestId,
   366→          assignmentDate,
   367→          error: error instanceof Error ? error.message : String(error),
   368→        },
   369→        'Failed to store run assignments'
   370→      );
   371→      // Don't throw - storage failure shouldn't fail the job
   372→      // The optimization itself succeeded
   373→    }
   374→  });
   375→}
